class Solution:
    def numOfUnplacedFruits(self, fruits, baskets):
        avail = list(baskets)
        unplaced = 0
        for q in fruits:
            placed = False
            for j in range(len(avail)):
                if avail[j] is not None and avail[j] >= q:
                    avail[j] = None
                    placed = True
                    break
            if not placed:
                unplaced += 1
        return unplaced

