var numOfUnplacedFruits = function(fruits, baskets) {
    const n = baskets.length;
    const used = new Array(n).fill(false);
    let unplaced = 0;
    for (const q of fruits) {
        let placed = false;
        for (let j = 0; j < n; j++) {
            if (!used[j] && baskets[j] >= q) {
                used[j] = true;
                placed = true;
                break;
            }
        }
        if (!placed) unplaced++;
    }
    return unplaced;
};
